module RefModule (
	input clk,
	input read_en,
	input write_en,
	input [2:0] addr,
	input [3:0] data_in,
	output reg [3:0] data_out);

	reg [3:0] unused_mem [7:0];

	always @(posedge clk) begin
		if (write_en)
			unused_mem[addr] <= data_in;
		if (read_en)
			data_out <= unused_mem[addr];
	end

endmodule
